// STEP 3 — Entity Association (the critical parsing step)
// Input: rows from the Spreadsheet File node (header row 11 → keys: Unit, Name,
// Amount Receivable, Last Payment, Payment Amount, 0-30, 30+, Rent, Primary Tenant Email).
// Output: ONE item per tenant data row, each with _entity_name and _property_address
// attached. Entity-header rows and subtotal/grand-total rows are consumed/skipped.
try {
  let currentEntity = '';
  let currentAddress = '';
  const tenantRows = [];

  for (const item of items) {
    const j = item.json || {};
    const unit = (j['Unit'] || '').toString().trim();
    const name = (j['Name'] || '').toString().trim();
    const amountReceivable = j['Amount Receivable'];

    // Skip fully empty rows
    if (!unit && !name && (amountReceivable === undefined || amountReceivable === null || amountReceivable === '')) {
      continue;
    }

    // Entity header row: Column A populated, Column B (Name) empty, contains " - "
    if (unit && !name && unit.includes(' - ')) {
      const parts = unit.split(' - ');
      currentEntity = parts[0].trim();
      currentAddress = parts.slice(1).join(' - ').trim();
      continue;
    }

    // Grand total row: Unit === "Total"
    if (unit === 'Total') {
      continue;
    }

    // Subtotal rows: no Name value (numeric-only rows after each entity group)
    if (!name || name === 'Total') {
      continue;
    }

    // Tenant data row — attach the current entity context
    j._entity_name = currentEntity;
    j._property_address = currentAddress;
    tenantRows.push({ json: j });
  }

  return tenantRows;
} catch (err) {
  // Surface a clear error so the Error Trigger path can report it
  throw new Error('Step 3 entity association failed: ' + (err && err.message ? err.message : String(err)));
}

// ═══════════════════════════════════════════════════════════════════
// SAFETY FLAGS — single source of truth. Change these to go live.
//   DRY_RUN=true  → every outreach email is redirected to TEST_EMAIL,
//                   all CC fields are emptied, log source is tagged "test",
//                   and the summary subject is prefixed "[TEST MODE]".
//   BATCH_LIMIT=5 → if more than 5 tenants qualify, NO emails are sent;
//                   an alert is sent to TEST_EMAIL instead.
// Going live requires THREE separate edits (do them one at a time):
//   1) swap the Gmail Trigger subject to the real AppFolio subject
//   2) set DRY_RUN = false
//   3) raise BATCH_LIMIT to the expected volume
// ═══════════════════════════════════════════════════════════════════
const DRY_RUN = true;
const BATCH_LIMIT = 5;
const TEST_EMAIL = 'jtsomwaru@gmail.com';

try {
  for (const item of items) {
    item.json._DRY_RUN = DRY_RUN;
    item.json._BATCH_LIMIT = BATCH_LIMIT;
    item.json._TEST_EMAIL = TEST_EMAIL;
  }
  return items;
} catch (err) {
  throw new Error('Safety Flags node failed: ' + (err && err.message ? err.message : String(err)));
}

// PROCESS & DECIDE — consolidates playbook Steps 4–12.
// Pulls the 112 tenant rows (with safety flags) and the four Google Sheets via
// node references, then computes: invalid-row filtering, balance ratio, 2x
// threshold, data-error flag (ratio>50), batch limit, Do-Not-Contact, manual
// contact, the escalation state machine (initial→follow_up→final→escalation),
// COI overlap, lease-vs-license wording, DRY_RUN routing, and the daily summary.
// Output: ONE item { _control, tenantsToEmail[], summary }.
try {
  // ---- gather inputs via explicit node references (Sheets/Code reset $json) ----
  const tenantItems = $('Safety Flags').all().map(i => i.json).filter(j => (j['Name'] || '').toString().trim());
  const flagsSrc = $('Safety Flags').first().json || {};
  const DRY_RUN = flagsSrc._DRY_RUN === true;
  const BATCH_LIMIT = Number(flagsSrc._BATCH_LIMIT) || 5;
  const TEST_EMAIL = flagsSrc._TEST_EMAIL || 'jtsomwaru@gmail.com';

  const safeAll = (name) => { try { return $(name).all().map(i => i.json || {}); } catch (e) { return []; } };
  const processingLog = safeAll('Read Processing Log');
  const outreachLog = safeAll('Read Outreach Log');
  const dncList = safeAll('Read Do Not Contact');
  const coiLog = safeAll('Read COI Alert Log');

  let messageId = '';
  try { messageId = ($('Gmail Trigger').first().json.id || '').toString(); } catch (e) { messageId = ''; }

  const today = DateTime.now().setZone('America/New_York');
  const todayStr = today.toFormat('yyyy-LL-dd');

  // license-agreement entities (use "license agreement" instead of "lease")
  const licenseEntities = ['Markland 486 LLC', 'Markland 713 LLC', 'Bronx Canvas LLC', 'Bronx Canvas Canal LLC'];

  const key = (n, u) => (n || '').toString().trim().toLowerCase() + '|' + (u || '').toString().trim().toLowerCase();

  // ---- already-processed check (dedupe by Gmail message id) ----
  const alreadyProcessed = !!messageId && processingLog.some(r =>
    (r.email_message_id || '').toString().trim() === messageId);

  // ---- Do-Not-Contact set ----
  const dncSet = new Set(dncList
    .filter(r => (r.tenant_name || '').toString().trim())
    .map(r => key(r.tenant_name, r.unit)));

  // ---- COI overlap (tenants alerted today) ----
  const coiTodaySet = new Set(coiLog
    .filter(r => {
      const d = (r.date_sent || r.alert_date || r.date || r.date_added || '').toString().slice(0, 10);
      return d === todayStr;
    })
    .map(r => key(r.tenant_name || r.name || r['Tenant Name'], r.unit || r.Unit)));

  // ---- index outreach log by tenant key ----
  const outreachByKey = {};
  for (const r of outreachLog) {
    const tn = r.tenant_name; const u = r.unit;
    if (!(tn || '').toString().trim()) continue;
    const k = key(tn, u);
    (outreachByKey[k] = outreachByKey[k] || []).push(r);
  }
  const daysSince = (dstr) => {
    if (!dstr) return null;
    const d = DateTime.fromFormat((dstr || '').toString().slice(0, 10), 'yyyy-LL-dd', { zone: 'America/New_York' });
    if (!d.isValid) return null;
    return Math.floor(today.diff(d, 'days').days);
  };

  // ---- accumulators ----
  const toEmail = [];
  const noEmail = [], badRent = [], dataError = [];
  const doNotContact = [], manuallyContacted = [], recentlyContacted = [];
  const escalationNeeded = [], coiOverlap = [];
  let belowThreshold = 0;
  let thresholdPassers = 0; // valid + ratio in [2,50]  (batch-limit basis, per Step 8)

  const tmin = (t) => ({ name: t.tenant_name, unit: t.unit, entity: t.entity_name, property: t.property_address });

  for (const j of tenantItems) {
    const name = (j['Name'] || '').toString().trim();
    const email = (j['Primary Tenant Email'] || '').toString().trim();
    const unit = (j['Unit'] || '').toString().trim();
    const entity = (j._entity_name || '').toString().trim();
    const address = (j._property_address || '').toString().trim();
    const rent = parseFloat(j['Rent']) || 0;
    const balance = parseFloat(j['Amount Receivable']) || 0;

    const base = { tenant_name: name, entity_name: entity, property_address: address, unit: unit,
      monthly_rent: rent, accrued_balance: balance };

    // Step 5a — no email
    if (!email) { noEmail.push(tmin(base)); continue; }
    // Step 5b — $0 or negative rent (cannot compute ratio)
    if (rent <= 0) { badRent.push(tmin(base)); continue; }

    // Step 6 — ratio
    const ratio = Math.round((balance / rent) * 100) / 100;
    base.balance_ratio = ratio;

    // Step 6 — data error (ratio > 50)
    if (ratio > 50) { dataError.push({ ...tmin(base), balance_ratio: ratio }); continue; }
    // Step 7 — threshold 2x
    if (ratio < 2) { belowThreshold++; continue; }

    // passed threshold and data-valid → counts toward batch limit (Step 8 basis)
    thresholdPassers++;

    // Step 9 — Do Not Contact
    if (dncSet.has(key(name, unit))) { doNotContact.push(tmin(base)); continue; }

    // Step 10 — outreach log: manual contact + cooldown/escalation
    const entries = (outreachByKey[key(name, unit)] || []).slice()
      .sort((a, b) => ((b.date_sent || '') + '').localeCompare((a.date_sent || '') + ''));
    if (entries.some(e => (e.manual_contact || '').toString().trim().toLowerCase() === 'yes')) {
      manuallyContacted.push(tmin(base)); continue;
    }
    const last = entries[0] || null;
    let stage = null;
    if (!last) {
      stage = 'initial_notice';
    } else {
      const lastStage = (last.escalation_stage || '').toString().trim();
      const d = daysSince(last.date_sent);
      if (lastStage === 'initial_notice' && d !== null && d >= 14) stage = 'follow_up';
      else if (lastStage === 'follow_up' && d !== null && d >= 7) stage = 'final_notice';
      else if (lastStage === 'final_notice' && d !== null && d >= 7) stage = 'escalation_needed';
      else { recentlyContacted.push({ ...tmin(base), last_stage: lastStage, days_since: d }); continue; }
    }

    if (stage === 'escalation_needed') {
      const d = daysSince(last && last.date_sent);
      escalationNeeded.push({ ...tmin(base), days_since_final: d });
      continue;
    }

    // COI overlap (informational — still send)
    if (coiTodaySet.has(key(name, unit))) coiOverlap.push(tmin(base));

    // Step 12 — lease vs license agreement
    const leaseOrLicense = licenseEntities.includes(entity) ? 'license agreement' : 'lease';

    // ---- build the outreach email (DRAFT placeholder templates) ----
    const money = (n) => '$' + Number(n).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    const disregard = 'If you have already made this payment, please disregard this message.';
    let subject = '', body = '';
    const head = `${name}\n${address}\nUnit ${unit}`;
    const figures = `Total balance due: ${money(balance)}\nMonthly rent: ${money(rent)}`;
    if (stage === 'initial_notice') {
      subject = `Past-Due Balance Notice — ${address} Unit ${unit}`;
      body = `[DRAFT TEMPLATE — Initial Notice — pending final copy from Yair]\n\nDear ${name},\n\nOur records show a past-due balance on your account for the property below.\n\n${head}\n\n${figures}\n\nPlease arrange payment at your earliest convenience. ${disregard}\n\nAltmark Group`;
    } else if (stage === 'follow_up') {
      subject = `Second Notice: Past-Due Balance — ${address} Unit ${unit}`;
      body = `[DRAFT TEMPLATE — Follow-Up Notice — pending final copy from Yair]\n\nDear ${name},\n\nThis is a follow-up to our recent notice regarding the past-due balance on your account, which remains outstanding.\n\n${head}\n\n${figures}\n\nPlease remit payment promptly. ${disregard}\n\nAltmark Group`;
    } else { // final_notice
      subject = `FINAL NOTICE: Past-Due Balance — ${address} Unit ${unit}`;
      body = `[DRAFT TEMPLATE — Final Notice — pending final copy from Yair]\n\nDear ${name},\n\nDespite previous notices, the past-due balance on your account remains unpaid. This is a final notice. Continued non-payment may constitute a violation of your ${leaseOrLicense}.\n\n${head}\n\n${figures}\n\nImmediate payment is required. ${disregard}\n\nAltmark Group`;
    }

    toEmail.push({
      tenant_name: name, entity_name: entity, property_address: address, unit: unit,
      monthly_rent: rent, accrued_balance: balance, balance_ratio: ratio,
      escalation_stage: stage, lease_or_license: leaseOrLicense,
      tenant_email: email,
      _send_to: DRY_RUN ? TEST_EMAIL : email,
      _cc: DRY_RUN ? '' : 'yair@altmarkgroup.com, matt@altmarkgroup.com',
      subject: (DRY_RUN ? '[TEST] ' : '') + subject,
      body: body,
      source: DRY_RUN ? 'test' : 'scheduled',
      date_sent: todayStr,
    });
  }

  const batchExceeded = thresholdPassers > BATCH_LIMIT;
  const proceed = !alreadyProcessed && !batchExceeded;
  const tenantsToEmail = proceed ? toEmail : [];
  const skippedAll = noEmail.length + badRent.length + dataError.length + doNotContact.length +
    manuallyContacted.length + recentlyContacted.length + escalationNeeded.length;

  const summary = {
    today: todayStr,
    dry_run: DRY_RUN,
    emails_sent: tenantsToEmail.map(t => ({ name: t.tenant_name, property: t.property_address, unit: t.unit,
      balance: t.accrued_balance, rent: t.monthly_rent, ratio: t.balance_ratio, stage: t.escalation_stage })),
    escalation_needed: escalationNeeded,
    recently_contacted: recentlyContacted,
    manually_contacted: manuallyContacted,
    do_not_contact: doNotContact,
    coi_overlap: coiOverlap,
    no_email: noEmail,
    bad_rent: badRent,
    data_error: dataError,
    totals: {
      tenants_in_report: tenantItems.length,
      meeting_threshold: thresholdPassers,
      outreach_sent: tenantsToEmail.length,
      skipped_all: skippedAll,
      below_threshold: belowThreshold,
    },
  };

  const _control = {
    already_processed: alreadyProcessed,
    batch_exceeded: batchExceeded,
    batch_size: thresholdPassers,
    batch_limit: BATCH_LIMIT,
    proceed: proceed,
    dry_run: DRY_RUN,
    test_email: TEST_EMAIL,
    message_id: messageId,
    today: todayStr,
    tenants_in_report: tenantItems.length,
    emails_sent_count: tenantsToEmail.length,
  };

  return [{ json: { _control, tenantsToEmail, summary } }];
} catch (err) {
  throw new Error('Process & Decide failed: ' + (err && err.message ? err.message : String(err)));
}

// BUILD BATCH ALERT — fired when more tenants qualify than BATCH_LIMIT allows.
// No outreach is sent; this alert goes to TEST_EMAIL so a human reviews first.
try {
  const c = ($json && $json._control) || {};
  const subject = `[ACTION NEEDED] Rent Delinquency batch size ${c.batch_size} exceeds limit of ${c.batch_limit}`;
  const body = `The rent delinquency workflow stopped without sending any emails.\n\n` +
    `Qualifying tenants (met 2x threshold, valid email/rent): ${c.batch_size}\n` +
    `Current BATCH_LIMIT: ${c.batch_limit}\n` +
    `Date: ${c.today}\n\n` +
    `No outreach emails were sent. If this volume is expected (e.g. first run / backlog), ` +
    `raise BATCH_LIMIT in the Safety Flags node and re-run. Otherwise investigate the report.`;
  return [{ json: { _send_to: c.test_email || 'jtsomwaru@gmail.com', _cc: '', subject, body } }];
} catch (err) {
  throw new Error('Build Batch Alert failed: ' + (err && err.message ? err.message : String(err)));
}

// EXPLODE TENANTS — turn the single decision item into one item per tenant to
// email (0..N). Downstream: log row → append → send. Empty list => no sends.
try {
  const ctrl = ($json && $json._control) || {};
  const list = ($json && Array.isArray($json.tenantsToEmail)) ? $json.tenantsToEmail : [];
  if (!ctrl.proceed || list.length === 0) return [];
  return list.map(t => ({ json: t, pairedItem: { item: 0 } }));
} catch (err) {
  throw new Error('Explode Tenants failed: ' + (err && err.message ? err.message : String(err)));
}

// PREP OUTREACH LOG ROW — flatten ONE tenant into the exact column names of the
// "Rent Delinquency Outreach Log" sheet. Runs once per item (auto-paired) so the
// downstream Gmail send can still reference $('Explode Tenants').item.
// Log is written BEFORE the email is sent (prevents duplicate sends on retry).
try {
  const t = $json || {};
  return {
    json: {
      tenant_name: t.tenant_name || '',
      entity_name: t.entity_name || '',
      property_address: t.property_address || '',
      unit: t.unit || '',
      monthly_rent: t.monthly_rent != null ? t.monthly_rent : '',
      accrued_balance: t.accrued_balance != null ? t.accrued_balance : '',
      balance_ratio: t.balance_ratio != null ? t.balance_ratio : '',
      escalation_stage: t.escalation_stage || '',
      date_sent: t.date_sent || '',
      source: t.source || '',
      manual_contact: '',
    },
  };
} catch (err) {
  throw new Error('Prep Outreach Log Row failed: ' + (err && err.message ? err.message : String(err)));
}

// PREP PROCESSING LOG ROW — one row recording that this report email was handled,
// with counts. Appending the message id here prevents the same report from being
// processed twice on a later poll.
try {
  const c = ($json && $json._control) || {};
  return {
    json: {
      email_message_id: c.message_id || '',
      date_processed: c.today || '',
      tenants_in_report: c.tenants_in_report != null ? c.tenants_in_report : '',
      emails_sent: c.emails_sent_count != null ? c.emails_sent_count : 0,
    },
  };
} catch (err) {
  throw new Error('Prep Processing Log Row failed: ' + (err && err.message ? err.message : String(err)));
}

// BUILD DAILY SUMMARY — render the summary email body/recipients from the single
// decision item. In DRY_RUN it goes to TEST_EMAIL with a [TEST MODE] subject;
// live it goes to Yair and Matt.
try {
  const c = ($json && $json._control) || {};
  const s = ($json && $json.summary) || {};
  const dry = c.dry_run === true;
  const t = s.totals || {};

  const line = (x) => '- ' + x;
  const tenantLine = (e) => `   ${e.name} | ${e.property} | Unit ${e.unit}`;
  const sentLine = (e) => `   ${e.name} | ${e.property} | Unit ${e.unit} | $${e.balance} | rent $${e.rent} | ratio ${e.ratio} | ${e.stage}`;
  const block = (title, arr, fmt) => {
    const a = arr || [];
    let out = `\n${title} (${a.length}):\n`;
    out += a.length ? a.map(fmt).join('\n') : '   (none)';
    return out + '\n';
  };

  let body = '';
  body += `RENT DELINQUENCY SUMMARY — ${c.today || ''}\n`;
  body += dry ? '*** DRY RUN — no tenants were contacted; all mail routed to the test address ***\n' : '';
  body += block('EMAILS SENT TODAY', s.emails_sent, sentLine);
  body += block('ESCALATION NEEDED — PERSONAL OUTREACH REQUIRED', s.escalation_needed,
    (e) => `   ${e.name} | ${e.property} | Unit ${e.unit} | days since final: ${e.days_since_final}`);
  body += block('SKIPPED — RECENTLY CONTACTED (cooldown not elapsed)', s.recently_contacted,
    (e) => `   ${e.name} | ${e.property} | Unit ${e.unit} | last: ${e.last_stage} (${e.days_since}d ago)`);
  body += block('SKIPPED — MANUALLY CONTACTED', s.manually_contacted, tenantLine);
  body += block('SKIPPED — DO NOT CONTACT', s.do_not_contact, tenantLine);
  body += block('COI OVERLAP WARNING (also received a COI email today)', s.coi_overlap, tenantLine);
  body += block('DATA ISSUES — NO EMAIL', s.no_email, tenantLine);
  body += block('DATA ISSUES — $0 / NEGATIVE RENT', s.bad_rent, tenantLine);
  body += block('DATA ISSUES — RATIO ABOVE 50 (likely data error)', s.data_error,
    (e) => `   ${e.name} | ${e.property} | Unit ${e.unit} | ratio ${e.balance_ratio}`);
  body += '\nREPORT TOTALS:\n';
  body += line(`Total tenants in report: ${t.tenants_in_report}`) + '\n';
  body += line(`Meeting 2x threshold: ${t.meeting_threshold}`) + '\n';
  body += line(`Outreach sent: ${t.outreach_sent}`) + '\n';
  body += line(`Skipped (all reasons): ${t.skipped_all}`) + '\n';
  body += line(`Below threshold: ${t.below_threshold}`) + '\n';

  const subject = (dry ? '[TEST MODE] ' : '') + `Rent Delinquency Summary — ${c.today || ''}`;
  return [{ json: {
    _send_to: dry ? (c.test_email || 'jtsomwaru@gmail.com') : 'yair@altmarkgroup.com, matt@altmarkgroup.com',
    _cc: '',
    subject: subject,
    body: body,
  } }];
} catch (err) {
  throw new Error('Build Summary failed: ' + (err && err.message ? err.message : String(err)));
}

// BUILD ERROR ALERT — runs on the Error Trigger path. Summarizes the failed
// node/execution and routes the alert to the test address (safe default).
try {
  const e = $json || {};
  const wf = (e.workflow && e.workflow.name) ? e.workflow.name : 'Rent Delinquency Outreach';
  const node = (e.execution && e.execution.lastNodeExecuted) ? e.execution.lastNodeExecuted : 'unknown node';
  const msg = (e.execution && e.execution.error && e.execution.error.message)
    ? e.execution.error.message : 'No error message available';
  const subject = `[WORKFLOW ERROR] ${wf} — failed at ${node}`;
  const body = `The "${wf}" workflow errored.\n\nFailed node: ${node}\nError: ${msg}\n\n` +
    `No further outreach was sent for this run. Review the n8n execution log.`;
  return [{ json: { _send_to: 'jtsomwaru@gmail.com', _cc: '', subject, body } }];
} catch (err) {
  return [{ json: { _send_to: 'jtsomwaru@gmail.com', _cc: '',
    subject: '[WORKFLOW ERROR] Rent Delinquency Outreach',
    body: 'The workflow errored and the error handler could not parse the details.' } }];
}
